// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.stream.IntStream;

import org.eclipse.rdf4j.model.Value;
import org.junit.jupiter.api.Test;

class FiniteDomainFactTest {

	@Test
	void canonicalizationUsesLinearMembershipInsteadOfPairwiseValueComparisons() {
		AtomicInteger stringValueCalls = new AtomicInteger();
		List<Value> values = IntStream.range(0, 512)
				.mapToObj(index -> (Value) new CountingValue("urn:test:value:" + index, stringValueCalls))
				.toList();

		FiniteDomainFact fact = FiniteDomainFact.exact(values, true, "complexity-regression");

		assertEquals(values.size(), fact.values().size());
		assertTrue(stringValueCalls.get() < values.size() * 32,
				() -> "Canonicalizing " + values.size() + " unique values performed " + stringValueCalls.get()
						+ " identity reads; finite-domain membership must not compare every value pair");
	}

	private record CountingValue(String lexicalValue, AtomicInteger stringValueCalls) implements Value {

		@Override
		public String stringValue() {
			stringValueCalls.incrementAndGet();
			return lexicalValue;
		}
	}
}
